package com.example.networking

import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Header

data class UserProfile(val id: String, val name: String, val email: String)

interface ApiService {
    @GET("users")
    suspend fun getUserProfiles(@Header("Authorization") token: String): List<UserProfile>
}

object ApiClient {
    private const val BASE_URL_DEV = "https://dev.api.example.com/"
    private const val BASE_URL_STAGING = "https://staging.api.example.com/"
    private const val BASE_URL_PROD = "https://api.example.com/"

    private val loggingInterceptor = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }

    private val authInterceptor = Interceptor { chain ->
        val request = chain.request().newBuilder()
            .addHeader("Authorization", "Bearer YOUR_API_TOKEN")
            .build()
        chain.proceed(request)
    }

    private fun getOkHttpClient() = OkHttpClient.Builder()
        .addInterceptor(loggingInterceptor)
        .addInterceptor(authInterceptor)
        .build()

    fun getApiService(environment: String): ApiService {
        val baseUrl = when (environment) {
            "dev" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            "prod" -> BASE_URL_PROD
            else -> BASE_URL_PROD
        }

        val retrofit = Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(getOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create())
            .build()

        return retrofit.create(ApiService::class.java)
    }
}